1	//! Shared plumbing for the MLX-backed primitives.
2	//!
3	//! Two classes of helper live here:
4	//!
5	//! 1. **Conversion** -- `dense_to_mlx` / `mlx_to_dense` round-trip
6	//!    an `mlpl-array` `DenseArray` through an `mlx_rs::Array` on
7	//!    the fp32 GPU/Accelerate path. Every op that touches MLX
8	//!    goes through these so the f64 <-> f32 boundary (and the
9	//!    `.eval()` call that materializes MLX's lazy graph) lives in
10	//!    exactly one place.
11	//!
12	//! 2. **Label propagation** -- `merge_labels` / `matmul_labels`
13	//!    mirror `mlpl-array`'s private helpers of the same names
14	//!    byte-for-byte (Saga 11.5 Phase 3 semantics). They live here
15	//!    so the MLX ops that need them (elementwise, matmul) can
16	//!    share a single source of truth and `mlpl-array`'s internal
17	//!    helpers stay internal.
18	
19	use mlpl_array::{ArrayError, DenseArray, Shape};
20	use mlx_rs::Array as MlxArray;
21	
22	/// Build an MLX fp32 array from an `mlpl-array` `DenseArray`.
23	///
24	/// The caller is responsible for any shape validation -- this
25	/// helper trusts `dims` and only handles the f64 -> f32 cast plus
26	/// the i32 dims conversion MLX expects.
27	pub(crate) fn dense_to_mlx(data: &[f64], dims: &[usize]) -> MlxArray {
28	    let data_f32: Vec<f32> = data.iter().map(|&x| x as f32).collect();
29	    let shape: Vec<i32> = dims.iter().map(|&d| d as i32).collect();
30	    MlxArray::from_slice(&data_f32, &shape)
31	}
32	
33	/// Materialize an MLX array and cast its flat contents back to f64.
34	///
35	/// `.eval()` forces MLX's lazy graph so `as_slice` sees real data.
36	/// The caller decides what shape (and labels) the resulting
37	/// `DenseArray` wears.
38	pub(crate) fn mlx_to_dense_data(mlx: MlxArray) -> Vec<f64> {
39	    mlx.eval()
40	        .expect("mlx eval on pre-validated shapes should not fail");
41	    let out: &[f32] = mlx.as_slice();
42	    out.iter().map(|&x| x as f64).collect()
43	}
44	
45	/// Finalize an MLX computation: wrap `data` in a `DenseArray` of
46	/// `shape` and attach `labels` if present. Consolidates the
47	/// DenseArray::new + with_labels dance every op does on the way out.
48	pub(crate) fn finalize(
49	    shape: Shape,
50	    data: Vec<f64>,
51	    labels: Option<Vec<Option<String>>>,
52	) -> Result<DenseArray, ArrayError> {
53	    let array = DenseArray::new(shape, data)?;
54	    match labels {
55	        Some(lbls) => array.with_labels(lbls),
56	        None => Ok(array),
57	    }
58	}
59	
60	/// Mirror of `mlpl-array`'s private `merge_labels` helper.
61	///
62	/// Scalars contribute no labels, so the non-scalar side's labels
63	/// win unconditionally when one operand is rank 0. For non-scalar
64	/// pairs, two unlabeled sides stay unlabeled, a single labeled
65	/// side carries its labels through, and two labeled sides must
66	/// agree or `LabelMismatch` is returned.
67	pub(crate) fn merge_labels(
68	    a: &DenseArray,
69	    b: &DenseArray,
70	) -> Result<Option<Vec<Option<String>>>, ArrayError> {
71	    if a.rank() == 0 {
72	        return Ok(b.labels().map(<[Option<String>]>::to_vec));
73	    }
74	    if b.rank() == 0 {
75	        return Ok(a.labels().map(<[Option<String>]>::to_vec));
76	    }
77	    match (a.labels(), b.labels()) {
78	        (None, None) => Ok(None),
79	        (Some(l), None) | (None, Some(l)) => Ok(Some(l.to_vec())),
80	        (Some(la), Some(lb)) if la == lb => Ok(Some(la.to_vec())),
81	        (Some(la), Some(lb)) => Err(ArrayError::LabelMismatch {
82	            expected: la.to_vec(),
83	            actual: lb.to_vec(),
84	        }),
85	    }
86	}
87	
88	/// Mirror of `mlpl-array`'s private `matmul_labels` helper.
89	/// Saga 11.5 Phase 3 semantics: contraction-axis labels must
90	/// agree, survivors are `[a.labels[0], b.labels[1]]`.
91	pub(crate) fn matmul_labels(
92	    a: &DenseArray,
93	    b: &DenseArray,
94	) -> Result<Option<Vec<Option<String>>>, ArrayError> {
95	    if a.labels().is_none() && b.labels().is_none() {
96	        return Ok(None);
97	    }
98	    let default_b = vec![None; b.rank()];
99	    let al: &[Option<String>] = a.labels().unwrap_or(&[None, None][..]);
100	    let bl: &[Option<String>] = b.labels().unwrap_or(default_b.as_slice());
101	    if let (Some(sa), Some(sb)) = (&al[1], &bl[0])
102	        && sa != sb
103	    {
104	        return Err(ArrayError::LabelMismatch {
105	            expected: al.to_vec(),
106	            actual: bl.to_vec(),
107	        });
108	    }
109	    let mut result = vec![al[0].clone()];
110	    if b.rank() == 2 {
111	        result.push(bl[1].clone());
112	    }
113	    Ok(Some(result))
114	}
