129	fn builtin_reduce(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
130	    if args.len() != 1 && args.len() != 2 {
131	        return Err(RuntimeError::ArityMismatch {
132	            func: name.into(),
133	            expected: 1,
134	            got: args.len(),
135	        });
136	    }
