}

#[test]
fn exp_matches_cpu_within_fp32_tolerance() {
    let a = DenseArray::new(
        Shape::new(vec![2, 3]),
        vec![0.0, 0.25, 0.5, -0.5, -0.25, 1.0],
    )
    .unwrap();
    let cpu = mlpl_rt::exp(&a);
