    let q = (b.matmul)(x, wq)?;
    let k = (b.matmul)(x, wk)?;
    let v = (b.matmul)(x, wv)?;
    let kt = (b.transpose)(&k);
    let scores = (b.matmul)(&q, &kt)?;
    let scale = 1.0 / (D as f64).sqrt();
    let mut masked = Vec::with_capacity(T * T);
