1	//! Reductions, normalisation, and loss primitives (Saga 14 step 003).
2	//!
3	//! Each function mirrors the runtime-target signature that the
4	//! `mlpl-mlx` sibling exposes, so compiled MLPL code can swap
5	//! runtimes without source changes. Semantics match the
6	//! interpreter's `mlpl-runtime` builtins by construction:
7	//! `softmax` and `log_softmax` use the same max-subtraction trick
8	//! for numerical stability, and `cross_entropy` is the matching
9	//! fused log-softmax + NLL with a scalar mean output.
10	//!
11	//! Label propagation follows Saga 11.5: a reduced axis drops its
12	//! label; `softmax` and `log_softmax` preserve labels (output
13	//! shape is unchanged); `cross_entropy` returns an unlabeled
14	//! scalar.
15	
16	use mlpl_array::{ArrayError, DenseArray, Shape};
17	
18	/// Product reduction. `axis = None` collapses to a scalar over the
19	/// flat data; `axis = Some(ax)` removes one dimension and returns a
20	/// rank-(r-1) array.
21	pub fn reduce_mul(a: &DenseArray, axis: Option<usize>) -> Result<DenseArray, ArrayError> {
22	    match axis {
23	        Some(ax) => a.reduce_axis(ax, 1.0, |x, y| x * y),
24	        None => Ok(DenseArray::from_scalar(a.data().iter().copied().product())),
25	    }
26	}
27	
28	/// Mean reduction. Flat = sum / elem_count (with elem_count clamped
29	/// to 1 for the empty case so the result is finite); axis-aware =
30	/// per-axis sum divided by the reduced axis size.
31	pub fn mean(a: &DenseArray, axis: Option<usize>) -> Result<DenseArray, ArrayError> {
32	    if let Some(ax) = axis {
33	        let dims = a.shape().dims();
34	        if ax >= dims.len() {
35	            return Err(ArrayError::IndexOutOfBounds {
36	                axis: ax,
37	                index: ax,
38	                size: dims.len(),
39	            });
40	        }
41	        let n = dims[ax].max(1) as f64;
42	        let s = a.reduce_axis(ax, 0.0, |x, y| x + y)?;
43	        let scaled: Vec<f64> = s.data().iter().map(|v| v / n).collect();
44	        return DenseArray::new(s.shape().clone(), scaled).and_then(|arr| match s.labels() {
45	            Some(lbls) => arr.with_labels(lbls.to_vec()),
46	            None => Ok(arr),
47	        });
48	    }
49	    let n = a.elem_count().max(1) as f64;
50	    let s: f64 = a.data().iter().sum();
51	    Ok(DenseArray::from_scalar(s / n))
52	}
53	
54	/// Index of the maximum value. Flat returns a rank-0 scalar holding
55	/// the flat index of the global max; axis-aware delegates to
56	/// `DenseArray::argmax_axis` (drops the chosen axis from the result).
57	/// Ties go to the first occurrence on both paths.
58	pub fn argmax(a: &DenseArray, axis: Option<usize>) -> Result<DenseArray, ArrayError> {
59	    if let Some(ax) = axis {
60	        return a.argmax_axis(ax);
61	    }
62	    let data = a.data();
63	    if data.is_empty() {
64	        return Err(ArrayError::EmptyArray);
65	    }
66	    let mut best_idx = 0usize;
67	    let mut best_val = data[0];
68	    for (i, &v) in data.iter().enumerate().skip(1) {
69	        if v > best_val {
70	            best_val = v;
71	            best_idx = i;
72	        }
73	    }
74	    Ok(DenseArray::from_scalar(best_idx as f64))
75	}
76	
77	/// `softmax(a, axis)`: exp-and-normalise along `axis` with the
78	/// max-subtraction trick for numerical stability. Output shape and
79	/// labels match the input.
80	pub fn softmax(a: &DenseArray, axis: usize) -> Result<DenseArray, ArrayError> {
81	    let dims = a.shape().dims().to_vec();
82	    if axis >= dims.len() {
83	        return Err(ArrayError::IndexOutOfBounds {
84	            axis,
85	            index: axis,
86	            size: dims.len(),
87	        });
88	    }
89	    let axis_size = dims[axis];
90	    let axis_stride: usize = dims.iter().skip(axis + 1).product();
91	    let group_count = (a.elem_count() / axis_size).max(1);
92	    let group_of = |flat: usize| {
93	        if axis_stride > 1 {
94	            (flat / (axis_size * axis_stride)) * axis_stride + (flat % axis_stride)
95	        } else {
96	            flat / axis_size
97	        }
98	    };
99	    let mut maxv = vec![f64::NEG_INFINITY; group_count];
100	    for (flat, &v) in a.data().iter().enumerate() {
101	        let g = group_of(flat);
102	        if v > maxv[g] {
103	            maxv[g] = v;
104	        }
105	    }
106	    let mut out = vec![0.0f64; a.elem_count()];
107	    let mut sums = vec![0.0f64; group_count];
108	    for (flat, slot) in out.iter_mut().enumerate() {
109	        let g = group_of(flat);
110	        let e = (a.data()[flat] - maxv[g]).exp();
111	        *slot = e;
112	        sums[g] += e;
113	    }
114	    for (flat, slot) in out.iter_mut().enumerate() {
115	        *slot /= sums[group_of(flat)];
116	    }
117	    let result = DenseArray::new(Shape::new(dims), out)?;
118	    match a.labels() {
119	        Some(lbls) => result.with_labels(lbls.to_vec()),
120	        None => Ok(result),
121	    }
122	}
