71	/// Index of the maximum value over `axis` (None = flat). The
72	/// MLX-side argmax returns an unsigned integer array; we cast it
73	/// to f32 so the f64 round trip in `mlx_to_dense_data` agrees with
74	/// the CPU path's `f64` index representation.
75	pub fn argmax(a: &DenseArray, axis: Option<usize>) -> Result<DenseArray, ArrayError> {
76	    if a.elem_count() == 0 && axis.is_none() {
77	        return Err(ArrayError::EmptyArray);
78	    }
79	    let mlx = dense_to_mlx(a.data(), a.shape().dims());
80	    let raw = if let Some(ax) = axis {
81	        let dims = a.shape().dims();
82	        if ax >= dims.len() {
83	            return Err(ArrayError::IndexOutOfBounds {
84	                axis: ax,
85	                index: ax,
86	                size: dims.len(),
87	            });
88	        }
89	        mlx_rs::ops::indexing::argmax_axis(&mlx, ax as i32, false)
90	            .expect("mlx argmax_axis on validated axis")
91	    } else {
92	        mlx_rs::ops::indexing::argmax(&mlx, false).expect("mlx argmax on non-empty array")
93	    };
94	    let as_f32 = raw
95	        .as_type::<f32>()
96	        .expect("argmax result casts to f32 for f64 round trip");
97	    let (out_dims, labels) = match axis {
98	        Some(ax) => drop_axis(a, ax),
99	        None => (vec![], None),
100	    };
101	    finalize(Shape::new(out_dims), mlx_to_dense_data(as_f32), labels)
102	}
