1	//! Saga 14 step 003 closing test: a Tiny LM forward pass routed
2	//! through the MLX runtime produces the same loss as the same
3	//! forward routed through `mlpl-rt`, within fp32 tolerance.
4	//!
5	//! The forward exercises every primitive the Saga 13 Tiny LM
6	//! `demos/tiny_lm.mlpl` uses through to its loss scalar:
7	//!
8	//!     embed -> positional -> rms_norm -> causal_attention
9	//!           -> residual -> rms_norm -> linear -> relu -> linear
10	//!           -> residual -> rms_norm -> linear -> cross_entropy
11	//!
12	//! The model is a single head, single block, scaled down to keep
13	//! the test cheap (V=8, d=4, T=4, ff_hidden=8) but structurally
14	//! identical to the demo. A `Backend` function-pointer table lets
15	//! the same forward run on either runtime; passing the test means
16	//! the MLX path produces the same loss as the CPU path on the
17	//! same fixed-seed parameters.
18	//!
19	//! Same triple-gate as the rest of `mlpl-mlx`: macOS + aarch64 +
20	//! `mlx` feature.
21	
22	#![cfg(all(target_os = "macos", target_arch = "aarch64", feature = "mlx"))]
23	
24	use mlpl_mlx::{ArrayError, DenseArray, Shape};
25	
26	/// Tolerance for the end-to-end forward parity. The Tiny LM
27	/// forward chains ~10 fp32-round-tripped MLX kernels; the
28	/// per-element error compounds roughly linearly. 5e-4 is loose
29	/// enough to absorb that compounding while still catching real
30	/// regressions.
31	const TINY_LM_TOL: f64 = 5e-4;
32	
33	/// Per-runtime function pointers for every primitive the forward
34	/// touches. Pure Rust scaffolding (slice_cols, rms_norm by hand,
35	/// mask construction) lives outside the table so it is shared
36	/// across runtimes verbatim.
37	struct Backend {
38	    matmul: fn(&DenseArray, &DenseArray) -> Result<DenseArray, ArrayError>,
39	    add: fn(&DenseArray, &DenseArray) -> Result<DenseArray, ArrayError>,
40	    softmax: fn(&DenseArray, usize) -> Result<DenseArray, ArrayError>,
41	    transpose: fn(&DenseArray) -> DenseArray,
42	    relu: fn(&DenseArray) -> DenseArray,
43	    cross_entropy: fn(&DenseArray, &DenseArray) -> Result<DenseArray, ArrayError>,
44	}
45	
46	/// CPU matmul wrapper -- `mlpl-rt` does not surface a free
47	/// `matmul` symbol because the compile-to-rust codegen lowers it
48	/// to a direct `DenseArray::matmul` method call. The MLX side does
49	/// have a free `mlpl_mlx::matmul`, so we wrap the CPU side here to
50	/// give the `Backend` table a uniform signature.
51	fn cpu_matmul(a: &DenseArray, b: &DenseArray) -> Result<DenseArray, ArrayError> {
52	    a.matmul(b)
53	}
54	
55	const MLPL_RT: Backend = Backend {
56	    matmul: cpu_matmul,
57	    add: mlpl_rt::add,
58	    softmax: mlpl_rt::softmax,
59	    transpose: mlpl_rt::transpose,
60	    relu: mlpl_rt::relu,
61	    cross_entropy: mlpl_rt::cross_entropy,
62	};
63	
64	const MLPL_MLX: Backend = Backend {
65	    matmul: mlpl_mlx::matmul,
66	    add: mlpl_mlx::add,
67	    softmax: mlpl_mlx::softmax,
68	    transpose: mlpl_mlx::transpose,
69	    relu: mlpl_mlx::relu,
70	    cross_entropy: mlpl_mlx::cross_entropy,
71	};
72	
73	#[test]
74	fn tiny_lm_forward_loss_matches_cpu_within_tolerance() {
75	    let p = Params::new();
76	    let cpu_loss = forward_loss(&MLPL_RT, &p).unwrap();
77	    let mlx_loss = forward_loss(&MLPL_MLX, &p).unwrap();
78	    assert_eq!(cpu_loss.shape().dims(), &[] as &[usize]);
79	    assert_eq!(mlx_loss.shape().dims(), &[] as &[usize]);
80	    let diff = (cpu_loss.data()[0] - mlx_loss.data()[0]).abs();
81	    assert!(
82	        diff <= TINY_LM_TOL,
83	        "tiny LM forward loss diverges: cpu={} mlx={} diff={} tol={TINY_LM_TOL}",
84	        cpu_loss.data()[0],
85	        mlx_loss.data()[0],
86	        diff
87	    );
88	}
